mapper.select:
SELECT s.* FROM site s LEFT JOIN site_employee_map sem ON sem.id_site = s.id WHERE sem.id_employee = 1 AND s.`status` = 1 AND s.is_delete = 0
AND s.id IN (
#{item}
)

SELECT t.categories_time, CAST(
AS DECIMAL ) AS monthlyProduction FROM (
SELECT s.dc_capacity, s.interval_energy_threshold, s.minimum_energy_value, CONVERT_TZ( dv.time, 'UTC', t.`value` ) AS time, AS categories_time, (
) AS monthlyProduction FROM ${item.datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone JOIN ( SELECT (
) AS currentTimeValid, (
) AS leadTimeValid, MIN(dv.time) AS minTime, MAX(dv.time) AS maxTime, LAG(MAX(dv.time), 1) OVER (ORDER BY dv.time) AS lagMaxTime FROM ${item.datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone WHERE s.id = #{item.id_site} AND s.`status` = 1 AND d.id = #{item.id} AND d.`status` = 1 AND d.id_device_type = #{item.id_device_type} AND dv.time BETWEEN CONVERT_TZ(#{start_date}, t.`value`, 'UTC') AND CONVERT_TZ(#{end_date}, t.`value`, 'UTC') AND dv.nvmActiveEnergy IS NOT NULL AND (CONVERT_TZ(NOW(), 'UTC', t.value) < s.expiration OR s.expiration IS NULL) GROUP BY
) m ON m.minTime = dv.time AND dv.id_device = #{item.id}
) t GROUP BY t.categories_time ORDER BY t.time
